import { useState, useMemo } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { useNavigate } from "react-router-dom";
import { toast } from "sonner";
import { Loader2, AlertCircle, AlertTriangle } from "lucide-react";
import { workScheduleService } from "@/api/workScheduleService";
import { userService } from "@/api/auth/userService";
import type { WorkScheduleResponse, TeamMember } from "@/features/work-schedule/types";
import { ApprovalsTab } from "@/features/work-schedule/components/ApprovalsTab";
import { HarmonyDialog } from "@/components/ui/harmony-dialog";
import { getApiErrorMessage } from "@/api/app/apiError";
import { COLOR_PALETTE } from "@/features/work-schedule/constants";
import { queryKeys } from '@/lib/queryKeys';
import { ROUTES } from '@/lib/routes';

export default function TeamScheduleApproval() {
  const navigate = useNavigate();
  const queryClient = useQueryClient();

  const [rejectTargetId, setRejectTargetId] = useState<string | null>(null);
  const [rejectTargetName, setRejectTargetName] = useState<string>("");
  const [rejectNotes, setRejectNotes] = useState("");
  const [isRejectModalOpen, setIsRejectModalOpen] = useState(false);
  const [unfreezeTargetId, setUnfreezeTargetId] = useState<string | null>(null);
  const [isUnfreezeModalOpen, setIsUnfreezeModalOpen] = useState(false);

  const { data: pendingSchedules = [], isLoading } = useQuery<WorkScheduleResponse[]>({
    queryKey: queryKeys.workSchedule.pendingApproval(),
    queryFn: () => workScheduleService.getPendingSchedulesForApproval() as Promise<WorkScheduleResponse[]>,
    refetchInterval: 30_000,
  });

  const { data: allUsers = [] } = useQuery({
    queryKey: queryKeys.teamMembers(),
    queryFn: async () => {
      const [employees, interns] = await Promise.all([
        userService.getEmployees(),
        userService.getInterns(),
      ]);
      return [...employees, ...interns];
    },
    staleTime: 1000 * 60 * 5,
  });

  const teamMembers = useMemo<TeamMember[]>(() =>
    allUsers.map((u, idx: number) => {
      const p = COLOR_PALETTE[idx % COLOR_PALETTE.length];
      return {
        id: u.id ?? u.userProfileId ?? "",
        name: u.fullName ?? u.firstName ?? u.email ?? "Unknown",
        fullName: u.fullName,
        email: u.email,
        bgClass: p.bgClass,
        hexColor: p.hexColor,
      };
    }),
  [allUsers]);

  const approveMutation = useMutation({
    mutationFn: (monthId: string) => workScheduleService.approveSchedule(monthId),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: queryKeys.workSchedule.pendingApproval() });
      toast.success("Schedule approved.");
    },
    onError: (err) => toast.error(getApiErrorMessage(err)),
  });

  const rejectMutation = useMutation({
    mutationFn: ({ monthId, notes }: { monthId: string; notes: string }) =>
      workScheduleService.rejectSchedule(monthId, notes),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: queryKeys.workSchedule.pendingApproval() });
      setIsRejectModalOpen(false);
      setRejectNotes("");
      setRejectTargetId(null);
    },
    onError: (err) => toast.error(getApiErrorMessage(err)),
  });

  const unfreezeMutation = useMutation({
    mutationFn: (monthId: string) => workScheduleService.unfreezeSchedule(monthId),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: queryKeys.workSchedule.pendingApproval() });
      setIsUnfreezeModalOpen(false);
      setUnfreezeTargetId(null);
      toast.success("Schedule unfrozen.");
    },
    onError: (err) => toast.error(getApiErrorMessage(err)),
  });

  return (
    <div className="space-y-6">
      <div className="section-card overflow-hidden">
        <div className="px-6 py-5 border-b border-border">
          <h1 className="text-base font-bold text-foreground">Schedule Approvals</h1>
          <p className="text-sm text-muted-foreground mt-0.5">Review and act on submitted work schedules</p>
        </div>

        {isLoading ? (
          <div className="flex items-center justify-center py-20">
            <Loader2 className="w-6 h-6 animate-spin text-primary" />
          </div>
        ) : (
          <ApprovalsTab
            teamSchedules={pendingSchedules}
            teamMembers={teamMembers}
            approveMutation={approveMutation}
            setRejectTargetId={setRejectTargetId}
            setRejectTargetName={setRejectTargetName}
            setRejectNotes={setRejectNotes}
            setIsRejectModalOpen={setIsRejectModalOpen}
            setUnfreezeTargetId={setUnfreezeTargetId}
            setIsUnfreezeModalOpen={setIsUnfreezeModalOpen}
            onViewClick={(schedule) => {
              const userId = schedule.userProfile?.id || schedule.userId;
              if (userId) navigate(`${ROUTES.workScheduleForUser(userId)}?year=${schedule.year}&month=${schedule.month}`);
            }}
          />
        )}
      </div>

      {/* ── Reject modal ── */}
      <HarmonyDialog
        open={isRejectModalOpen}
        onOpenChange={(open) => { if (!open) { setIsRejectModalOpen(false); setRejectNotes(""); setRejectTargetId(null); } }}
        title="Reject Schedule"
        description={rejectTargetName || ""}
        size="md"
        onSubmit={() => rejectTargetId && rejectNotes.trim() && rejectMutation.mutate({ monthId: rejectTargetId, notes: rejectNotes.trim() })}
        submitLabel="Confirm Reject"
        isSubmitting={rejectMutation.isPending}
        submitDisabled={!rejectNotes.trim()}
      >
        <div className="space-y-5">
          <p className="text-foreground text-sm leading-relaxed font-medium">
            Please provide a reason for rejection. This note will be visible to the team member.
          </p>
          <div>
            <label className="ws-label">Review Notes <span className="text-rose-500">*</span></label>
            <textarea
              value={rejectNotes}
              onChange={(e) => setRejectNotes(e.target.value)}
              placeholder="e.g. Please update weekend coverage for the 15th…"
              rows={4}
              className="w-full px-4 py-3 border border-border rounded-2xl text-sm text-foreground placeholder:text-muted-foreground font-medium focus:outline-none focus:ring-2 focus:ring-destructive/30 focus:border-destructive transition-all resize-none bg-muted/30"
            />
          </div>
          {rejectMutation.isError && (
            <div className="p-3.5 bg-destructive/10 border border-destructive/20 rounded-xl flex items-start gap-2.5">
              <AlertCircle className="w-4 h-4 text-destructive shrink-0 mt-0.5" />
              <p className="text-destructive text-sm font-medium">{getApiErrorMessage(rejectMutation.error)}</p>
            </div>
          )}
        </div>
      </HarmonyDialog>

      {/* ── Unfreeze modal ── */}
      <HarmonyDialog
        open={isUnfreezeModalOpen}
        onOpenChange={(open) => { if (!open) { setIsUnfreezeModalOpen(false); setUnfreezeTargetId(null); } }}
        title="Unfreeze Schedule"
        size="md"
        onSubmit={() => unfreezeTargetId && unfreezeMutation.mutate(unfreezeTargetId)}
        submitLabel="Unfreeze Schedule"
        isSubmitting={unfreezeMutation.isPending}
      >
        <div className="space-y-4">
          <p className="text-foreground text-sm font-medium leading-relaxed">
            This will unlock the approved schedule, allowing the employee to make changes again.
          </p>
          <div className="p-4 bg-amber-50 border border-amber-200/80 rounded-2xl flex items-start gap-3">
            <div className="w-6 h-6 bg-amber-100 rounded-lg flex items-center justify-center shrink-0 mt-0.5">
              <AlertTriangle className="w-3.5 h-3.5 text-amber-600" />
            </div>
            <p className="text-amber-800 text-sm font-medium leading-relaxed">
              The schedule status will be reset to Draft. The employee will need to resubmit for approval.
            </p>
          </div>
          {unfreezeMutation.isError && (
            <div className="p-3.5 bg-destructive/10 border border-destructive/20 rounded-xl flex items-start gap-2.5">
              <AlertCircle className="w-4 h-4 text-destructive shrink-0 mt-0.5" />
              <p className="text-destructive text-sm font-medium">{getApiErrorMessage(unfreezeMutation.error)}</p>
            </div>
          )}
        </div>
      </HarmonyDialog>
    </div>
  );
}
